// Script to test browser visualization
console.log('Using browser endpoint:', $node["Config"].json.browserWSEndpoint);
console.log('Navigating to:', $node["Config"].json.testUrl);

// Slow down operations for visibility
async function slowDown(ms = 1000) {
  console.log(`Waiting ${ms}ms for visibility...`);
  return new Promise(resolve => setTimeout(resolve, ms));
}

// Initial navigation
await $page.goto($node["Config"].json.testUrl, { waitUntil: 'networkidle0' });
await slowDown(2000);

// Click the Public Access button if it exists
try {
  console.log('Looking for Public Access button...');
  const publicAccessButton = await $page.waitForSelector('a:has-text("Click Here for Public Access")', { timeout: 5000 });
  if (publicAccessButton) {
    console.log('Clicking Public Access button...');
    await publicAccessButton.click();
    await $page.waitForNavigation({ waitUntil: 'networkidle0' });
    await slowDown(2000);
  }
} catch (error) {
  console.log('No Public Access button found or error clicking it:', error.message);
}

// Check if agreement overlay appears and click "agree" if it does
try {
  console.log('Looking for agreement button...');
  const agreeButton = await $page.waitForSelector('input[value="I Agree"]', { timeout: 5000 });
  if (agreeButton) {
    console.log('Clicking agree button...');
    await agreeButton.click();
    await $page.waitForNavigation({ waitUntil: 'networkidle0' });
    await slowDown(2000);
  }
} catch (error) {
  console.log('No agreement dialog found or error clicking it:', error.message);
}

// Wait for the search form to load
try {
  console.log('Waiting for search form...');
  await $page.waitForSelector('select[name="selectmun"]', { timeout: 10000 });
  console.log('Search form found!');
  await slowDown(1000);

  // Test filling out form with a sample SBL
  const sbl = '106-1-10-100'; // Example SBL
  let sblParts = sbl.split('-');

  // Select Ulster municipality (106 = Ulster)
  console.log('Selecting municipality...');
  await $page.select('select[name="selectmun"]', '106');
  await slowDown(1000);

  // Fill in SBL parts
  console.log('Filling in SBL fields...');
  await $page.type('input[name="swis"]', sblParts[0]);
  await slowDown(500);
  await $page.type('input[name="section"]', sblParts[1]);
  await slowDown(500);
  await $page.type('input[name="block"]', sblParts[2]);
  await slowDown(500);
  await $page.type('input[name="lot"]', sblParts[3]);
  await slowDown(1000);

  // Click search button
  console.log('Clicking search button...');
  const searchButton = await $page.waitForSelector('input[value="Search"]');
  await searchButton.click();

  // Wait for results
  await $page.waitForNavigation({ waitUntil: 'networkidle0' });
  await slowDown(2000);

  // Take a screenshot
  console.log('Taking screenshot...');
  const screenshot = await $page.screenshot({ type: 'png', encoding: 'base64' });

  return [
    {
      success: true,
      message: 'Browser test completed successfully',
      binary: {
        screenshot: {
          data: screenshot,
          mimeType: 'image/png',
          fileName: 'ulster_county_test.png'
        }
      }
    }
  ];

} catch (error) {
  console.log('Error during test:', error.message);
  // Take a screenshot of the error state
  const errorScreenshot = await $page.screenshot({ type: 'png', encoding: 'base64' });

  return [
    {
      success: false,
      error: error.message,
      binary: {
        errorScreenshot: {
          data: errorScreenshot,
          mimeType: 'image/png',
          fileName: 'error_screenshot.png'
        }
      }
    }
  ];
}
